let _seed = 42
function seededRandom(): number {
  _seed = (_seed * 16807 + 0) % 2147483647
  return (_seed - 1) / 2147483646
}

function randomFrom<T>(arr: readonly T[]): T {
  return arr[Math.floor(seededRandom() * arr.length)]
}

